                m = int(s[:2]); d = int(s[3:])
                return sum(md[:m - 1]) + d
            return set(range(ordinal(a), ordinal(b) + 1))
        return len(days_set(arriveAlice, leaveAlice) & days_set(arriveBob, leaveBob))

