        md = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
        def ordinal(s):
            m = int(s[:2]); d = int(s[3:])
            return sum(md[:m - 1]) + d
        lo = max(ordinal(arriveAlice), ordinal(arriveBob))
        hi = min(ordinal(leaveAlice), ordinal(leaveBob))
