var countDaysTogether = function(arriveAlice, leaveAlice, arriveBob, leaveBob) {
    const md = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    const ordinal = (s) => {
        const m = parseInt(s.slice(0, 2), 10);
        const d = parseInt(s.slice(3), 10);
        let total = d;
        for (let i = 0; i < m - 1; i++) total += md[i];
        return total;
    };
    const lo = Math.max(ordinal(arriveAlice), ordinal(arriveBob));
    const hi = Math.min(ordinal(leaveAlice), ordinal(leaveBob));
    return Math.max(0, hi - lo + 1);
};
